import{_ as t,o as s,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"Newsletters and Unsubscribing","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/newsletters.md","filePath":"en/guide/newsletters.md"}'),l={name:"en/guide/newsletters.md"};function n(i,e,o,c,h,d){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="newsletters-and-unsubscribing" tabindex="-1">Newsletters and Unsubscribing <a class="header-anchor" href="#newsletters-and-unsubscribing" aria-label="Permalink to &quot;Newsletters and Unsubscribing&quot;">​</a></h1><p>Nid helps you identify the newsletters and mailing lists you&#39;re subscribed to, then clean them up in bulk.</p><hr><h2 id="scan-for-newsletters" tabindex="-1">Scan for Newsletters <a class="header-anchor" href="#scan-for-newsletters" aria-label="Permalink to &quot;Scan for Newsletters&quot;">​</a></h2><ol><li>Open the <strong>Newsletters</strong> page in the sidebar</li><li>Click <strong>Scan</strong> on the Gmail account of your choice</li><li>A scan job is launched — it analyzes the <code>List-Unsubscribe</code> headers of your recent emails</li></ol><blockquote><p>📸 <em>Suggested screenshot: Newsletters page before the scan, with the Scan button</em></p></blockquote><hr><h2 id="detected-newsletters-list" tabindex="-1">Detected Newsletters List <a class="header-anchor" href="#detected-newsletters-list" aria-label="Permalink to &quot;Detected Newsletters List&quot;">​</a></h2><p>After the scan, Nid displays a list of all detected newsletters, showing for each:</p><ul><li><strong>Sender</strong>: the newsletter&#39;s sending address</li><li><strong>Email count</strong>: how many emails you&#39;ve received from this sender</li><li><strong>Total size</strong>: the space occupied by these emails</li></ul><p>The list is sorted by email count in descending order, highlighting the most intrusive newsletters.</p><blockquote><p>📸 <em>Suggested screenshot: list of detected newsletters with sender, email count, and size columns</em></p></blockquote><hr><h2 id="view-emails-from-a-newsletter" tabindex="-1">View Emails from a Newsletter <a class="header-anchor" href="#view-emails-from-a-newsletter" aria-label="Permalink to &quot;View Emails from a Newsletter&quot;">​</a></h2><p>Click on a sender to see the list of all emails received from that newsletter. This lets you review the content before deciding to clean up.</p><hr><h2 id="clean-up-newsletters" tabindex="-1">Clean Up Newsletters <a class="header-anchor" href="#clean-up-newsletters" aria-label="Permalink to &quot;Clean Up Newsletters&quot;">​</a></h2><p>For each newsletter, two deletion options are available:</p><h3 id="move-to-trash" tabindex="-1">Move to Trash <a class="header-anchor" href="#move-to-trash" aria-label="Permalink to &quot;Move to Trash&quot;">​</a></h3><p>Moves all emails from this sender to Gmail&#39;s trash. Emails can be recovered for 30 days.</p><h3 id="permanently-delete" tabindex="-1">Permanently Delete <a class="header-anchor" href="#permanently-delete" aria-label="Permalink to &quot;Permanently Delete&quot;">​</a></h3><p>Permanently deletes all emails from this sender. This action is <strong>irreversible</strong>.</p><blockquote><p>📸 <em>Suggested screenshot: action buttons on a newsletter (Trash / Permanently Delete)</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Also unsubscribe from the sender</p><p>Nid detects newsletters but does not handle unsubscribing from the sender itself. Open the latest email from the newsletter and click the unsubscribe link at the bottom of the email to stop receiving new emails.</p></div><hr><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Scan regularly</strong> to detect new newsletters</li><li><strong>Start with trash</strong> rather than permanent deletion</li><li>Combine with an <strong>automatic rule</strong> to automatically delete future emails from a newsletter (see <a href="./rules.html">Rules</a>)</li></ol>',27)])])}const b=t(l,[["render",n]]);export{m as __pageData,b as default};
